{
  "name": "SmartReply Composer",
  "description": "A sophisticated response generation tool that creates customizable, modular message parts including greetings, body text, expressions of gratitude, and closing remarks tailored to any topic and tone."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum MessageTone {
  PROFESSIONAL = 'Professional',
  FORMAL = 'Formal',
  FRIENDLY = 'Friendly',
  CASUAL = 'Casual',
  ENTHUSIASTIC = 'Enthusiastic',
  APOLOGETIC = 'Apologetic'
}

export interface MessageParts {
  greetings: string[];
  bodies: string[];
  thanks: string[];
  closings: string[];
}

export interface SelectedParts {
  greeting: string;
  body: string;
  thanks: string;
  closing: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { MessageTone, MessageParts } from "./types";

const API_KEY = process.env.API_KEY;

export const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  if (!API_KEY) {
    throw new Error("API Key not found in environment.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate diverse response options for the following topic: "${topic}". Use a ${tone} tone. Provide multiple variations for greetings, the main message body, expressions of gratitude, and closing remarks. Ensure they are idiomatic and natural.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse greeting variations",
          },
          bodies: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse message body variations focused on the topic",
          },
          thanks: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse expressions of gratitude variations",
          },
          closings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse closing remark variations",
          }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      },
    },
  });

  try {
    const data = JSON.parse(response.text);
    return data as MessageParts;
  } catch (error) {
    console.error("Failed to parse JSON response from Gemini", error);
    throw new Error("Invalid response format from AI");
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import { generateMessageParts } from './geminiService';
import { MessageTone, MessageParts, SelectedParts } from './types';
import { 
  Sparkles, 
  Copy, 
  Check, 
  RefreshCw, 
  MessageSquare, 
  ChevronRight,
  Send,
  User,
  Coffee,
  Briefcase,
  Heart,
  AlertCircle
} from 'lucide-react';

const App: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [tone, setTone] = useState<MessageTone>(MessageTone.PROFESSIONAL);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<MessageParts | null>(null);
  const [selected, setSelected] = useState<SelectedParts>({
    greeting: '',
    body: '',
    thanks: '',
    closing: ''
  });
  const [copied, setCopied] = useState(false);

  const handleGenerate = async () => {
    if (!topic.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const data = await generateMessageParts(topic, tone);
      setResults(data);
      // Automatically select the first of each to provide an initial preview
      setSelected({
        greeting: data.greetings[0],
        body: data.bodies[0],
        thanks: data.thanks[0],
        closing: data.closings[0]
      });
    } catch (err: any) {
      setError(err.message || 'An error occurred while generating variations.');
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    const fullText = `${selected.greeting}\n\n${selected.body}\n\n${selected.thanks}\n\n${selected.closing}`;
    navigator.clipboard.writeText(fullText.trim());
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const updateSelection = (field: keyof SelectedParts, value: string) => {
    setSelected(prev => ({ ...prev, [field]: value }));
  };

  const getToneIcon = (t: MessageTone) => {
    switch (t) {
      case MessageTone.PROFESSIONAL: return <Briefcase size={16} />;
      case MessageTone.FORMAL: return <User size={16} />;
      case MessageTone.FRIENDLY: return <Coffee size={16} />;
      case MessageTone.CASUAL: return <Sparkles size={16} />;
      case MessageTone.ENTHUSIASTIC: return <Send size={16} />;
      case MessageTone.APOLOGETIC: return <Heart size={16} />;
      default: return <MessageSquare size={16} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <Sparkles size={20} />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">SmartReply Composer</h1>
          </div>
          <div className="hidden sm:block text-sm text-slate-500 font-medium">
            AI-Powered Message Orchestrator
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Input Controls */}
        <section className="lg:col-span-4 space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mb-4">Configuration</h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1.5">What is the context/topic?</label>
                <textarea
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  placeholder="e.g., Thanking a client for a project, declining a meeting, asking for feedback..."
                  className="w-full h-32 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none resize-none text-sm"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Desired Tone</label>
                <div className="grid grid-cols-2 gap-2">
                  {Object.values(MessageTone).map((t) => (
                    <button
                      key={t}
                      onClick={() => setTone(t)}
                      className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-all border ${
                        tone === t 
                          ? 'bg-indigo-50 border-indigo-200 text-indigo-700' 
                          : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      {getToneIcon(t)}
                      {t}
                    </button>
                  ))}
                </div>
              </div>

              <button
                onClick={handleGenerate}
                disabled={loading || !topic.trim()}
                className="w-full py-3.5 px-4 bg-indigo-600 hover:bg-indigo-700 disabled:bg-slate-300 text-white rounded-xl font-semibold shadow-lg shadow-indigo-200 flex items-center justify-center gap-2 transition-all active:scale-[0.98]"
              >
                {loading ? (
                  <RefreshCw size={20} className="animate-spin" />
                ) : (
                  <>
                    <Sparkles size={20} />
                    Generate Variants
                  </>
                )}
              </button>

              {error && (
                <div className="flex items-start gap-2 p-3 bg-red-50 text-red-700 rounded-lg text-xs">
                  <AlertCircle size={16} className="mt-0.5 flex-shrink-0" />
                  <p>{error}</p>
                </div>
              )}
            </div>
          </div>

          <div className="bg-indigo-900 text-white p-6 rounded-2xl shadow-xl hidden lg:block">
            <h3 className="text-lg font-bold mb-2">Pro Tip</h3>
            <p className="text-indigo-100 text-sm leading-relaxed">
              Mix and match different variants to create the perfect response. The AI ensures each part maintains the consistency of your selected tone.
            </p>
          </div>
        </section>

        {/* Builder Interface */}
        <section className="lg:col-span-8 space-y-6">
          {!results ? (
            <div className="h-full min-h-[400px] flex flex-col items-center justify-center text-center p-8 border-2 border-dashed border-slate-200 rounded-3xl bg-white/50">
              <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center text-slate-400 mb-4">
                <MessageSquare size={32} />
              </div>
              <h3 className="text-lg font-medium text-slate-600">Your composer is empty</h3>
              <p className="text-slate-400 max-w-sm mt-2">
                Enter a topic and select a tone on the left to generate customized message variations.
              </p>
            </div>
          ) : (
            <div className="space-y-6">
              {/* Message Parts Selection */}
              <div className="grid gap-6">
                {[
                  { label: 'Salutation', field: 'greeting', items: results.greetings },
                  { label: 'Body Text', field: 'body', items: results.bodies },
                  { label: 'Gratitude', field: 'thanks', items: results.thanks },
                  { label: 'Closing', field: 'closing', items: results.closings }
                ].map((section) => (
                  <div key={section.field} className="space-y-3">
                    <div className="flex items-center justify-between px-1">
                      <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest">{section.label}</h3>
                      <span className="text-[10px] bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full font-bold">SELECT ONE</span>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                      {section.items.map((item, idx) => (
                        <button
                          key={idx}
                          onClick={() => updateSelection(section.field as keyof SelectedParts, item)}
                          className={`text-left p-4 rounded-xl text-sm border transition-all duration-200 hover:shadow-md ${
                            selected[section.field as keyof SelectedParts] === item
                              ? 'bg-white border-indigo-500 ring-2 ring-indigo-500/20 shadow-lg shadow-indigo-100'
                              : 'bg-white border-slate-200 hover:border-slate-300 text-slate-600'
                          }`}
                        >
                          {item}
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              {/* Final Preview Card */}
              <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden mt-10">
                <div className="bg-slate-50 border-b border-slate-200 px-6 py-4 flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-red-400"></div>
                    <div className="w-3 h-3 rounded-full bg-yellow-400"></div>
                    <div className="w-3 h-3 rounded-full bg-green-400"></div>
                    <span className="ml-2 text-xs font-bold text-slate-400 uppercase tracking-widest">Composer Preview</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <button
                      onClick={copyToClipboard}
                      className={`flex items-center gap-2 px-4 py-2 rounded-full text-xs font-bold transition-all ${
                        copied 
                          ? 'bg-green-500 text-white' 
                          : 'bg-indigo-600 text-white hover:bg-indigo-700'
                      }`}
                    >
                      {copied ? <Check size={14} /> : <Copy size={14} />}
                      {copied ? 'Copied!' : 'Copy Message'}
                    </button>
                  </div>
                </div>
                <div className="p-8 bg-white min-h-[300px] font-serif leading-relaxed text-slate-800 text-lg">
                  <p className="mb-6">{selected.greeting}</p>
                  <p className="mb-6">{selected.body}</p>
                  <p className="mb-6">{selected.thanks}</p>
                  <p>{selected.closing}</p>
                </div>
                <div className="p-4 bg-slate-50 border-t border-slate-100 flex items-center justify-center gap-6">
                  <span className="text-xs text-slate-400 italic">Generated with {tone} intent</span>
                </div>
              </div>
            </div>
          )}
        </section>
      </main>

      {/* Persistent Call to Action for Mobile */}
      {results && (
        <div className="sm:hidden fixed bottom-0 left-0 right-0 p-4 bg-white border-t border-slate-200 flex gap-2">
          <button
            onClick={copyToClipboard}
            className="flex-1 bg-indigo-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2"
          >
            {copied ? <Check size={18} /> : <Copy size={18} />}
            {copied ? 'Copied' : 'Copy All'}
          </button>
          <button
            onClick={handleGenerate}
            className="bg-slate-100 text-slate-600 p-3 rounded-xl"
          >
            <RefreshCw size={18} />
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

export enum MessageTone {
  PROFESSIONAL = 'Professional',
  FORMAL = 'Formal',
  FRIENDLY = 'Friendly',
  CASUAL = 'Casual',
  ENTHUSIASTIC = 'Enthusiastic',
  APOLOGETIC = 'Apologetic'
}

export interface MessageParts {
  greetings: string[];
  bodies: string[];
  thanks: string[];
  closings: string[];
}

export interface SelectedParts {
  greeting: string;
  body: string;
  thanks: string;
  closing: string;
}

export interface Scenario {
  id: string;
  label: string;
  topic: string;
  icon: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { MessageTone, MessageParts } from "./types";

const API_KEY = process.env.API_KEY;

export const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  if (!API_KEY) {
    throw new Error("API Key not found in environment.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate diverse, modular response segments for the following context: "${topic}". 
    The tone should be ${tone}. 

    Return exactly 3 variations for each of these 4 specific sections:
    1. GREETINGS: Professional opening salutations.
    2. BODY: The core message content (ensure these are variations of the same core information).
    3. GRATITUDE: Expressions of thanks or appreciation for cooperation.
    4. CLOSINGS: Professional sign-offs.

    Focus on business efficiency and clarity.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse professional greeting variations",
          },
          bodies: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse message body variations centered on the specific topic",
          },
          thanks: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse professional thanks/cooperation variations",
          },
          closings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse professional closing sign-off variations",
          }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      },
    },
  });

  try {
    const data = JSON.parse(response.text);
    return data as MessageParts;
  } catch (error) {
    console.error("Failed to parse JSON response from Gemini", error);
    throw new Error("Invalid response format from AI");
  }
};

import React, { useState, useEffect } from 'react';
import { generateMessageParts } from './geminiService';
import { MessageTone, MessageParts, SelectedParts, Scenario } from './types';
import { 
  Sparkles, 
  Copy, 
  Check, 
  RefreshCw, 
  MessageSquare, 
  Send,
  User,
  Coffee,
  Briefcase,
  Heart,
  AlertCircle,
  Clock,
  ShieldCheck,
  HelpCircle,
  XCircle,
  CheckCircle2
} from 'lucide-react';

const SCENARIOS: Scenario[] = [
  { id: 'working', label: 'Working on it', topic: 'We are working on the matter / Incident processing', icon: 'Clock' },
  { id: 'resolved', label: 'Issue Resolved', topic: 'The issue has been fixed and tested', icon: 'CheckCircle2' },
  { id: 'feedback', label: 'Request Feedback', topic: 'Asking if the solution works or for more details', icon: 'HelpCircle' },
  { id: 'declined', label: 'Request Declined', topic: 'Politely declining a request or meeting', icon: 'XCircle' },
  { id: 'security', label: 'Security Alert', topic: 'Informing about a security update or protocol', icon: 'ShieldCheck' },
];

const App: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [tone, setTone] = useState<MessageTone>(MessageTone.PROFESSIONAL);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<MessageParts | null>(null);
  const [selected, setSelected] = useState<SelectedParts>({
    greeting: '',
    body: '',
    thanks: '',
    closing: ''
  });
  const [copied, setCopied] = useState(false);

  const handleGenerate = async (targetTopic?: string) => {
    const currentTopic = targetTopic || topic;
    if (!currentTopic.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const data = await generateMessageParts(currentTopic, tone);
      setResults(data);
      setSelected({
        greeting: data.greetings[0],
        body: data.bodies[0],
        thanks: data.thanks[0],
        closing: data.closings[0]
      });
    } catch (err: any) {
      setError(err.message || 'An error occurred while generating variations.');
    } finally {
      setLoading(false);
    }
  };

  const handleScenarioClick = (s: Scenario) => {
    setTopic(s.topic);
    handleGenerate(s.topic);
  };

  const copyToClipboard = () => {
    const fullText = `${selected.greeting}\n\n${selected.body}\n\n${selected.thanks}\n\n${selected.closing}`;
    navigator.clipboard.writeText(fullText.trim());
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const updateSelection = (field: keyof SelectedParts, value: string) => {
    setSelected(prev => ({ ...prev, [field]: value }));
  };

  const getScenarioIcon = (iconName: string) => {
    switch (iconName) {
      case 'Clock': return <Clock size={18} />;
      case 'CheckCircle2': return <CheckCircle2 size={18} />;
      case 'HelpCircle': return <HelpCircle size={18} />;
      case 'XCircle': return <XCircle size={18} />;
      case 'ShieldCheck': return <ShieldCheck size={18} />;
      default: return <MessageSquare size={18} />;
    }
  };

  const getToneIcon = (t: MessageTone) => {
    switch (t) {
      case MessageTone.PROFESSIONAL: return <Briefcase size={16} />;
      case MessageTone.FORMAL: return <User size={16} />;
      case MessageTone.FRIENDLY: return <Coffee size={16} />;
      case MessageTone.CASUAL: return <Sparkles size={16} />;
      case MessageTone.ENTHUSIASTIC: return <Send size={16} />;
      case MessageTone.APOLOGETIC: return <Heart size={16} />;
      default: return <MessageSquare size={16} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <Sparkles size={20} />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">SmartReply Composer</h1>
          </div>
          <div className="text-sm font-medium px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full">
            Response Architect v2.0
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Sidebar: Controls */}
        <section className="lg:col-span-4 space-y-6">
          {/* Quick Scenarios */}
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h2 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Clock size={14} /> Quick Scenarios
            </h2>
            <div className="grid grid-cols-1 gap-2">
              {SCENARIOS.map((s) => (
                <button
                  key={s.id}
                  onClick={() => handleScenarioClick(s)}
                  className="flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all border border-slate-100 bg-slate-50 hover:bg-white hover:border-indigo-300 hover:shadow-md text-slate-700 text-left"
                >
                  <span className="text-indigo-500">{getScenarioIcon(s.icon)}</span>
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          {/* Custom Config */}
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h2 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Sparkles size={14} /> Custom Topic
            </h2>
            <div className="space-y-4">
              <textarea
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                placeholder="Or type any topic here..."
                className="w-full h-24 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none resize-none text-sm bg-slate-50 focus:bg-white"
              />

              <div>
                <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Desired Tone</label>
                <div className="grid grid-cols-2 gap-2">
                  {Object.values(MessageTone).map((t) => (
                    <button
                      key={t}
                      onClick={() => setTone(t)}
                      className={`flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-semibold transition-all border ${
                        tone === t 
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-100' 
                          : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      {getToneIcon(t)}
                      {t}
                    </button>
                  ))}
                </div>
              </div>

              <button
                onClick={() => handleGenerate()}
                disabled={loading || !topic.trim()}
                className="w-full py-3.5 px-4 bg-slate-900 hover:bg-black disabled:bg-slate-300 text-white rounded-xl font-bold shadow-xl shadow-slate-200 flex items-center justify-center gap-2 transition-all active:scale-[0.98]"
              >
                {loading ? <RefreshCw size={20} className="animate-spin" /> : 'Generate Custom'}
              </button>

              {error && (
                <div className="flex items-start gap-2 p-3 bg-red-50 text-red-700 rounded-lg text-xs border border-red-100">
                  <AlertCircle size={16} className="mt-0.5 flex-shrink-0" />
                  <p>{error}</p>
                </div>
              )}
            </div>
          </div>
        </section>

        {/* Right Content: Builder & Preview */}
        <section className="lg:col-span-8 space-y-8">
          {!results ? (
            <div className="h-full min-h-[500px] flex flex-col items-center justify-center text-center p-8 border-2 border-dashed border-slate-200 rounded-[2rem] bg-white/50 backdrop-blur-sm">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-400 mb-6 animate-pulse">
                <MessageSquare size={40} />
              </div>
              <h3 className="text-2xl font-bold text-slate-700">Ready to Compose</h3>
