import { GoogleGenAI, Type } from "@google/genai";
import { MessageTone, MessageParts } from "./types";

const API_KEY = process.env.API_KEY;

export const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  if (!API_KEY) {
    throw new Error("API Key not found in environment.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate diverse, modular response segments for the following context: "${topic}". 
    The tone should be ${tone}. 

    CRITICAL INSTRUCTIONS:
    1. GREETINGS: You MUST ONLY provide exactly these two options: "Dear Partner" and "Dear Customer".
    2. BODY: Provide 3 variations of the core message content.
    3. GRATITUDE: Provide 3 professional variations (e.g., "Thank you for your cooperation", "We remain at your disposal").
    4. CLOSINGS: Provide professional sign-offs (e.g., "Kind regards", "Best regards").

    Return exactly 2 greeting options and 3 options for all other fields.
    Focus on business efficiency and clarity.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Strictly only 'Dear Partner' and 'Dear Customer'",
          },
          bodies: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse message body variations centered on the specific topic",
          },
          thanks: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse professional thanks/cooperation variations",
          },
          closings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "3 diverse professional closing sign-off variations",
          }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      },
    },
  });

  try {
    const data = JSON.parse(response.text);
    // Safety check to ensure user requirements are met even if AI hallucinates
    if (data.greetings.length === 0) {
      data.greetings = ["Dear Partner", "Dear Customer"];
    }
    return data as MessageParts;
  } catch (error) {
    console.error("Failed to parse JSON response from Gemini", error);
    throw new Error("Invalid response format from AI");
  }
};

