                  onClick={() => handleScenarioClick(s)}
                  className="group flex items-center justify-between px-4 py-4 rounded-xl text-sm font-semibold transition-all border border-slate-100 bg-slate-50 hover:bg-white hover:border-indigo-300 hover:shadow-xl text-slate-700 text-left"
                >
                  <div className="flex items-center gap-3">
                    <span className="text-indigo-500">{getScenarioIcon(s.icon)}</span>
                    {s.label}
                  </div>
                  <Sparkles size={14} className="opacity-0 group-hover:opacity-100 transition-opacity text-indigo-400" />
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h2 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Sparkles size={14} /> Custom Topic & Tone
            </h2>
            <div className="space-y-4">
              <textarea
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                placeholder="Type any custom topic here..."
                className="w-full h-24 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none resize-none text-sm bg-slate-50 focus:bg-white font-medium"
              />

              <div className="relative">
                <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                  <PenTool size={16} />
                </div>
                <input
                  type="text"
                  value={responderName}
                  onChange={(e) => setResponderName(e.target.value)}
                  placeholder="Your Name (Optional)"
                  className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none text-sm bg-slate-50 focus:bg-white font-medium"
                />
              </div>

              <div className="grid grid-cols-2 gap-2">
                {Object.values(MessageTone).map((t) => (
                  <button
                    key={t}
                    onClick={() => setTone(t)}
                    className={getToneStyles(t, tone === t)}
                  >
                    {getToneIcon(t)}
                    {t}
                  </button>
                ))}
              </div>

              <button
                onClick={() => handleGenerate()}
                disabled={loading || !topic.trim()}
                className="w-full py-4 px-4 bg-slate-900 hover:bg-black disabled:bg-slate-300 text-white rounded-xl font-bold shadow-xl flex items-center justify-center gap-2 transition-all active:scale-95 mt-2"
              >
                {loading ? <RefreshCw size={20} className="animate-spin" /> : 'Apply Changes'}
              </button>

              {error && (
                <div className="flex items-start gap-2 p-3 bg-red-50 text-red-700 rounded-lg text-xs border border-red-100">
                  <AlertCircle size={16} className="mt-0.5 flex-shrink-0" />
                  <p>{error}</p>
                </div>
              )}
            </div>
          </div>
        </section>

        {/* Right Content: Builder & Preview */}
        <section className="lg:col-span-8 space-y-8">
          {!results ? (
            <div className="h-full min-h-[500px] flex flex-col items-center justify-center text-center p-8 border-2 border-dashed border-slate-200 rounded-[2.5rem] bg-white/50 backdrop-blur-sm">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-400 mb-6 animate-pulse">
                <MessageSquare size={40} />
              </div>
              <h3 className="text-2xl font-bold text-slate-700 tracking-tight">Select a Scenario</h3>
              <p className="text-slate-400 max-w-sm mt-3 leading-relaxed">
                Choose a pre-defined scenario from the left or type your own to start building your message.
              </p>
            </div>
          ) : (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 relative">
              {loading && (
                <div className="absolute inset-0 bg-white/40 backdrop-blur-[2px] z-50 flex items-center justify-center rounded-3xl">
                   <div className="bg-white p-4 rounded-full shadow-xl">
                      <RefreshCw size={32} className="animate-spin text-indigo-600" />
                   </div>
                </div>
              )}

              <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-black text-slate-900 tracking-tight">Compose Response</h2>
                <div className="px-4 py-1.5 rounded-full bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-lg">
                  <div className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse"></div>
                  {tone} Mood
                </div>
              </div>

              {/* Selection Modules */}
              <div className="space-y-8">
                {[
                  { label: 'Salutation', field: 'greeting', items: results.greetings },
                  { label: 'Message Body', field: 'body', items: results.bodies },
                  { label: 'Closing Courtesy', field: 'thanks', items: results.thanks },
                  { label: 'Final Signature', field: 'closing', items: results.closings }
                ].map((section) => (
                  <div key={section.field} className="space-y-3">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] ml-1">{section.label}</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                      {section.items.map((item, idx) => (
                        <button
                          key={idx}
                          onClick={() => updateSelection(section.field as keyof SelectedParts, item)}
                          className={`text-left p-5 rounded-[1.25rem] text-sm border transition-all duration-300 relative group min-h-[100px] flex items-center ${
                            selected[section.field as keyof SelectedParts] === item
                              ? 'bg-white border-indigo-600 ring-4 ring-indigo-500/10 shadow-xl scale-[1.02] z-10'
                              : 'bg-white border-slate-100 hover:border-indigo-200 hover:shadow-lg text-slate-600 shadow-sm'
                          }`}
                        >
                          {selected[section.field as keyof SelectedParts] === item && (
                            <div className="absolute top-3 right-3 text-indigo-600 bg-indigo-50 rounded-full p-0.5">
                              <CheckCircle2 size={16} />
                            </div>
                          )}
                          <p className="leading-relaxed font-semibold pr-4 text-sm">
                            {item}
                          </p>
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              {/* Final Preview & Action */}
              <div className="mt-16 group relative">
                <div className="flex items-center justify-between mb-4 px-2">
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <Send size={14} className="text-indigo-500" /> Preview (Click box to copy)
                  </h3>
                  <button
                    onClick={copyToClipboard}
                    className={`flex items-center gap-2 px-6 py-3 rounded-full text-sm font-bold transition-all shadow-xl hover:-translate-y-1 active:scale-95 z-20 ${
                      copied 
                        ? 'bg-green-500 text-white' 
                        : 'bg-slate-900 text-white hover:bg-black'
                    }`}
                  >
                    {copied ? <Check size={18} /> : <Copy size={18} />}
                    {copied ? 'Copied!' : 'Copy Entire Text'}
                  </button>
                </div>

                <div 
                  onClick={copyToClipboard}
                  className={`cursor-pointer group relative bg-white rounded-[2.5rem] border-2 transition-all duration-500 p-10 md:p-14 shadow-2xl overflow-hidden hover:border-indigo-500/50 ${
                    copied ? 'border-green-500' : 'border-slate-100'
                  }`}
                >
                  <div className={`absolute inset-0 bg-green-500/5 transition-opacity duration-300 ${copied ? 'opacity-100' : 'opacity-0'}`}></div>

                  <div className="absolute top-10 right-10 text-slate-100 group-hover:text-indigo-50 transition-colors">
                    <Copy size={100} strokeWidth={1} />
                  </div>

                  <div className="relative z-10 space-y-6 max-w-3xl mx-auto font-serif">
                    <p className="text-2xl text-slate-800 font-bold tracking-tight">{selected.greeting}</p>
                    <div className="py-6 border-l-4 border-indigo-500 pl-8 bg-slate-50/50 rounded-r-2xl shadow-inner">
                      <p className="text-xl text-slate-700 leading-relaxed italic">
                        {selected.body}
                      </p>
                    </div>
                    <p className="text-xl text-slate-700 font-medium">{selected.thanks}</p>
                    <div className="pt-8 border-t border-slate-100 space-y-1">
                      <p className="text-xl font-black text-slate-900">{selected.closing}</p>
                      {responderName.trim() && (
                        <p className="text-xl font-medium text-slate-600">{responderName}</p>
                      )}
                    </div>
                  </div>

                  <div className="absolute bottom-6 right-10 flex items-center gap-2 text-[10px] font-black text-slate-300 uppercase tracking-widest group-hover:text-indigo-400 transition-colors">
                    Click anywhere to copy
                  </div>
                </div>
              </div>
            </div>
          )}
        </section>
      </main>
    </div>
  );
};

export default App;

export enum MessageTone {
  PROFESSIONAL = 'Professional',
  FRIENDLY = 'Friendly',
  CASUAL = 'Casual',
  APOLOGETIC = 'Apologetic'
}

export interface MessageParts {
  greetings: string[];
  bodies: string[];
  thanks: string[];
  closings: string[];
}

export interface SelectedParts {
  greeting: string;
  body: string;
  thanks: string;
  closing: string;
}

export interface Scenario {
  id: string;
  label: string;
  topic: string;
  icon: string;
}

import React, { useState, useEffect } from 'react';
import { generateMessageParts } from './geminiService';
import { MessageTone, MessageParts, SelectedParts, Scenario } from './types';
import { 
  Sparkles, 
  Copy, 
  Check, 
  RefreshCw, 
  MessageSquare, 
  Send,
  Coffee,
  Briefcase,
  Heart,
  AlertCircle,
  Clock,
  CheckCircle2,
  PenTool
} from 'lucide-react';

const SCENARIOS: Scenario[] = [
  { id: 'working', label: 'Working on it', topic: 'We are working on the matter / Incident processing', icon: 'Clock' },
  { id: 'closure', label: 'Ticket Closure', topic: 'We proceed to close the ticket', icon: 'CheckCircle2' },
];

const App: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [tone, setTone] = useState<MessageTone>(MessageTone.PROFESSIONAL);
  const [responderName, setResponderName] = useState(() => localStorage.getItem('responderName') || '');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<MessageParts | null>(null);
  const [selected, setSelected] = useState<SelectedParts>({
    greeting: '',
    body: '',
    thanks: '',
    closing: ''
  });
  const [copied, setCopied] = useState(false);

  // Persist name in localStorage
  useEffect(() => {
    localStorage.setItem('responderName', responderName);
  }, [responderName]);

  // Re-generate automatically when tone changes if a topic exists
  useEffect(() => {
    if (topic && results) {
      handleGenerate(topic);
    }
  }, [tone]);

  const handleGenerate = async (targetTopic?: string) => {
    const currentTopic = targetTopic || topic;
    if (!currentTopic.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const data = await generateMessageParts(currentTopic, tone);
      setResults(data);
      setSelected({
        greeting: data.greetings[0] || 'Dear Customer',
        body: data.bodies[0] || '',
        thanks: data.thanks[0] || '',
        closing: data.closings[0] || 'Best regards'
      });
    } catch (err: any) {
      setError(err.message || 'An error occurred while generating variations.');
    } finally {
      setLoading(false);
    }
  };

  const handleScenarioClick = (s: Scenario) => {
    setTopic(s.topic);
    handleGenerate(s.topic);
  };

  const copyToClipboard = () => {
    const signature = responderName.trim() ? `\n${responderName}` : '';
    const fullText = `${selected.greeting}\n\n${selected.body}\n\n${selected.thanks}\n\n${selected.closing}${signature}`;
    navigator.clipboard.writeText(fullText.trim());
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const updateSelection = (field: keyof SelectedParts, value: string) => {
    setSelected(prev => ({ ...prev, [field]: value }));
  };

  const getScenarioIcon = (iconName: string) => {
    switch (iconName) {
      case 'Clock': return <Clock size={18} />;
      case 'CheckCircle2': return <CheckCircle2 size={18} />;
      default: return <MessageSquare size={18} />;
    }
  };

  const getToneIcon = (t: MessageTone) => {
    switch (t) {
      case MessageTone.PROFESSIONAL: return <Briefcase size={16} />;
      case MessageTone.FRIENDLY: return <Coffee size={16} />;
      case MessageTone.CASUAL: return <Sparkles size={16} />;
      case MessageTone.APOLOGETIC: return <Heart size={16} />;
      default: return <MessageSquare size={16} />;
    }
  };

  const getToneStyles = (t: MessageTone, active: boolean) => {
    const base = "flex items-center gap-2 px-3 py-2.5 rounded-xl text-xs font-bold border transition-all duration-300 ";
    const activeShadow = " shadow-lg scale-105 ";
    const inactive = " border-slate-200 text-slate-600 hover:border-slate-300 hover:bg-slate-50 ";

    switch (t) {
      case MessageTone.PROFESSIONAL:
        return base + (active ? "bg-indigo-600 border-indigo-600 text-white " + activeShadow : inactive);
      case MessageTone.FRIENDLY:
        return base + (active ? "bg-emerald-600 border-emerald-600 text-white " + activeShadow : inactive);
      case MessageTone.CASUAL:
        return base + (active ? "bg-rose-500 border-rose-500 text-white " + activeShadow : inactive);
      case MessageTone.APOLOGETIC:
        return base + (active ? "bg-purple-600 border-purple-600 text-white " + activeShadow : inactive);
      default:
        return base + (active ? "bg-slate-800 border-slate-800 text-white " + activeShadow : inactive);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg text-white">
              <Sparkles size={20} />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800 uppercase">SmartReply Composer</h1>
          </div>
          <div className="text-sm font-medium px-3 py-1 bg-indigo-50 text-indigo-700 rounded-full hidden sm:block">
            Modular Content Generator
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Sidebar: Controls */}
        <section className="lg:col-span-4 space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h2 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Clock size={14} /> Scenarios
            </h2>
            <div className="grid grid-cols-1 gap-2">
              {SCENARIOS.map((s) => (
                <button
                  key={s.id}
                  onClick={() => handleScenarioClick(s)}
                  className="group flex items-center justify-between px-4 py-4 rounded-xl text-sm font-semibold transition-all border border-slate-100 bg-slate-50 hover:bg-white hover:border-indigo-300 hover:shadow-xl text-slate-700 text-left"
                >
                  <div className="flex items-center gap-3">
                    <span className="text-indigo-500">{getScenarioIcon(s.icon)}</span>
                    {s.label}
                  </div>
                  <Sparkles size={14} className="opacity-0 group-hover:opacity-100 transition-opacity text-indigo-400" />
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h2 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Sparkles size={14} /> Custom Topic & Tone
            </h2>
            <div className="space-y-4">
              <textarea
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                placeholder="Type any custom topic here..."
                className="w-full h-24 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none resize-none text-sm bg-slate-50 focus:bg-white font-medium"
              />

              <div className="relative">
                <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                  <PenTool size={16} />
                </div>
                <input
                  type="text"
                  value={responderName}
                  onChange={(e) => setResponderName(e.target.value)}
                  placeholder="Your Name (Optional)"
                  className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none text-sm bg-slate-50 focus:bg-white font-medium"
                />
              </div>

              <div className="grid grid-cols-2 gap-2">
                {Object.values(MessageTone).map((t) => (
                  <button
                    key={t}
                    onClick={() => setTone(t)}
                    className={getToneStyles(t, tone === t)}
                  >
                    {getToneIcon(t)}
                    {t}
                  </button>
                ))}
              </div>

              <button
                onClick={() => handleGenerate()}
                disabled={loading || !topic.trim()}
                className="w-full py-4 px-4 bg-slate-900 hover:bg-black disabled:bg-slate-300 text-white rounded-xl font-bold shadow-xl flex items-center justify-center gap-2 transition-all active:scale-95 mt-2"
              >
                {loading ? <RefreshCw size={20} className="animate-spin" /> : 'Apply Changes'}
              </button>

              {error && (
                <div className="flex items-start gap-2 p-3 bg-red-50 text-red-700 rounded-lg text-xs border border-red-100">
                  <AlertCircle size={16} className="mt-0.5 flex-shrink-0" />
                  <p>{error}</p>
                </div>
              )}
            </div>
          </div>
        </section>

        {/* Right Content: Builder & Preview */}
        <section className="lg:col-span-8 space-y-8">
          {!results ? (
            <div className="h-full min-h-[500px] flex flex-col items-center justify-center text-center p-8 border-2 border-dashed border-slate-200 rounded-[2.5rem] bg-white/50 backdrop-blur-sm">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-400 mb-6 animate-pulse">
                <MessageSquare size={40} />
              </div>
              <h3 className="text-2xl font-bold text-slate-700 tracking-tight">Select a Scenario</h3>
              <p className="text-slate-400 max-w-sm mt-3 leading-relaxed">
                Choose a pre-defined scenario from the left or type your own to start building your message.
              </p>
            </div>
          ) : (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 relative">
              {loading && (
                <div className="absolute inset-0 bg-white/40 backdrop-blur-[2px] z-50 flex items-center justify-center rounded-3xl">
                   <div className="bg-white p-4 rounded-full shadow-xl">
                      <RefreshCw size={32} className="animate-spin text-indigo-600" />
                   </div>
                </div>
              )}

              <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-black text-slate-900 tracking-tight">Compose Response</h2>
                <div className="px-4 py-1.5 rounded-full bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-lg">
                  <div className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse"></div>
                  {tone} Mood
                </div>
              </div>

              {/* Selection Modules */}
              <div className="space-y-8">
                {[
                  { label: 'Salutation', field: 'greeting', items: results.greetings },
                  { label: 'Message Body', field: 'body', items: results.bodies },
                  { label: 'Closing Courtesy', field: 'thanks', items: results.thanks },
                  { label: 'Final Signature', field: 'closing', items: results.closings }
                ].map((section) => (
                  <div key={section.field} className="space-y-3">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] ml-1">{section.label}</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                      {section.items.map((item, idx) => (
                        <button
                          key={idx}
                          onClick={() => updateSelection(section.field as keyof SelectedParts, item)}
                          className={`text-left p-5 rounded-[1.25rem] text-sm border transition-all duration-300 relative group min-h-[100px] flex items-center ${
                            selected[section.field as keyof SelectedParts] === item
                              ? 'bg-white border-indigo-600 ring-4 ring-indigo-500/10 shadow-xl scale-[1.02] z-10'
                              : 'bg-white border-slate-100 hover:border-indigo-200 hover:shadow-lg text-slate-600 shadow-sm'
                          }`}
                        >
                          {selected[section.field as keyof SelectedParts] === item && (
                            <div className="absolute top-3 right-3 text-indigo-600 bg-indigo-50 rounded-full p-0.5">
                              <CheckCircle2 size={16} />
                            </div>
                          )}
                          <p className="leading-relaxed font-semibold pr-4 text-sm">
                            {item}
                          </p>
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>

              {/* Final Preview & Action */}
              <div className="mt-16 group relative">
                <div className="flex items-center justify-between mb-4 px-2">
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <Send size={14} className="text-indigo-500" /> Preview (Click box to copy)
                  </h3>
                  <button
                    onClick={copyToClipboard}
                    className={`flex items-center gap-2 px-6 py-3 rounded-full text-sm font-bold transition-all shadow-xl hover:-translate-y-1 active:scale-95 z-20 ${
                      copied 
                        ? 'bg-green-500 text-white' 
                        : 'bg-slate-900 text-white hover:bg-black'
                    }`}
                  >
                    {copied ? <Check size={18} /> : <Copy size={18} />}
                    {copied ? 'Copied!' : 'Copy Entire Text'}
                  </button>
                </div>

                <div 
                  onClick={copyToClipboard}
                  className={`cursor-pointer group relative bg-white rounded-[2.5rem] border-2 transition-all duration-500 p-10 md:p-14 shadow-2xl overflow-hidden hover:border-indigo-500/50 ${
                    copied ? 'border-green-500' : 'border-slate-100'
                  }`}
                >
                  <div className={`absolute inset-0 bg-green-500/5 transition-opacity duration-300 ${copied ? 'opacity-100' : 'opacity-0'}`}></div>

                  <div className="absolute top-10 right-10 text-slate-100 group-hover:text-indigo-50 transition-colors">
                    <Copy size={100} strokeWidth={1} />
                  </div>

                  <div className="relative z-10 space-y-6 max-w-3xl mx-auto font-serif">
                    <p className="text-2xl text-slate-800 font-bold tracking-tight">{selected.greeting}</p>
                    <div className="py-6 border-l-4 border-indigo-500 pl-8 bg-slate-50/50 rounded-r-2xl shadow-inner">
                      <p className="text-xl text-slate-700 leading-relaxed italic">
                        {selected.body}
                      </p>
                    </div>
                    <p className="text-xl text-slate-700 font-medium">{selected.thanks}</p>
                    <div className="pt-8 border-t border-slate-100 space-y-1">
                      <p className="text-xl font-black text-slate-900">{selected.closing}</p>
                      {responderName.trim() && (
                        <p className="text-xl font-medium text-slate-600">{responderName}</p>
                      )}
                    </div>
                  </div>

                  <div className="absolute bottom-6 right-10 flex items-center gap-2 text-[10px] font-black text-slate-300 uppercase tracking-widest group-hover:text-indigo-400 transition-colors">
                    Click anywhere to copy
                  </div>
                </div>
              </div>
            </div>
          )}
        </section>
      </main>
    </div>
  );
