    const base = "flex items-center gap-2 px-3 py-2.5 rounded-xl text-xs font-bold border transition-all duration-300 ";
    const activeShadow = " shadow-lg scale-105 ";
    const inactive = " border-slate-200 text-slate-600 hover:border-slate-300 hover:bg-slate-50 ";

    switch (t) {
      case MessageTone.PROFESSIONAL:
        return base + (active ? "bg-indigo-600 border-indigo-600 text-white " + activeShadow : inactive);
      case MessageTone.FRIENDLY:
        return base + (active ? "bg-emerald-600 border-emerald-600 text-white " + activeShadow : inactive);
      case MessageTone.CASUAL:
        return base + (active ? "bg-rose-500 border-rose-500 text-white " + activeShadow : inactive);
      case MessageTone.APOLOGETIC:
        return base + (active ? "bg-purple-600 border-purple-600 text-white " + activeShadow : inactive);
      default:
        return base + (active ? "bg-slate-800 border-slate-800 text-white " + activeShadow : inactive);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
