              <div className="grid grid-cols-2 gap-2">
                {Object.values(MessageTone).map((t) => (
                  <button
                    key={t}
                    onClick={() => setTone(t)}
                    className={getToneStyles(t, tone === t)}
                  >
                    {getToneIcon(t)}
                    {t}
                  </button>
                ))}
              </div>

              <button
                onClick={() => handleGenerate()}
