import { GoogleGenAI, Type } from "@google/genai";
import { MessageTone, MessageParts } from "./types";

const API_KEY = process.env.API_KEY;

export const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  if (!API_KEY) {
    throw new Error("API Key not found in environment.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // Define base templates to guide the AI for specific scenarios
  const isWorkingOnIt = topic.toLowerCase().includes("working") || topic.toLowerCase().includes("incident processing");
  const isClosure = topic.toLowerCase().includes("close") || topic.toLowerCase().includes("closure");

  let baseInstructions = "";
  if (isWorkingOnIt) {
    baseInstructions = `
      USE THESE SPECIFIC BASE TEMPLATES for the BODY variations:
      1. "Please be informed that your incident request is currently being processed. An update will follow as soon as possible."
      2. "Your request is under investigation. We will provide updates as soon as possible."
      Create 3 variations total, keeping the meaning and structure very close to these standard phrases.
    `;
  } else if (isClosure) {
    baseInstructions = `
      USE THESE SPECIFIC BASE TEMPLATES for the BODY variations:
      1. "We have successfully completed the request and are now proceeding to close the ticket."
      2. "The reported issue has been resolved. We are now closing this incident."
      Create 3 variations total, keeping the meaning and structure very close to these standard phrases.
    `;
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate diverse, modular response segments for the following context: "${topic}". 
    The tone should be ${tone}. 

    ${baseInstructions}

    CRITICAL INSTRUCTIONS:
    1. GREETINGS: Provide exactly "Dear Partner" and "Dear Customer".
    2. BODY: Provide 3 variations. If standard templates were provided above, stick closely to them with only minor adjustments for the requested tone (${tone}).
    3. GRATITUDE: Provide 3 professional variations (e.g., "Thank you for your cooperation", "We remain at your disposal").
    4. CLOSINGS: Provide 3 professional sign-offs (e.g., "Kind regards", "Best regards").

    Focus on business efficiency and clarity. Do not deviate significantly from the standard phrasing provided.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          bodies: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          thanks: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          closings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      },
    },
  });

  try {
    const data = JSON.parse(response.text);
    // Ensure greetings list is never empty
    if (!data.greetings || data.greetings.length === 0) {
      data.greetings = ["Dear Partner", "Dear Customer"];
    }
    return data as MessageParts;
  } catch (error) {
    console.error("Failed to parse JSON response from Gemini", error);
    throw new Error("Invalid response format from AI");
  }
};

