import { GoogleGenAI, Type } from "@google/genai";
import { MessageTone, MessageParts } from "./types";

const API_KEY = process.env.API_KEY;

export const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  if (!API_KEY) {
    throw new Error("API Key not found in environment.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `The user has provided a base message in either English or Italian: "${topic}".

    TASK:
    1. If the input is in Italian, translate the core meaning to professional English.
    2. If the input is in English, use it as the direct foundation.
    3. Generate 3 professional variations of this body text in ENGLISH. 
    4. The variations should reflect the tone: ${tone}.

    CRITICAL CONSTRAINTS:
    - ALWAYS output in ENGLISH.
    - GREETINGS: Provide exactly "Dear Partner" and "Dear Customer".
    - BODY: 3 variations, staying close to the user's provided meaning but polished for a ${tone} professional environment.
    - CLOSING COURTESY (thanks): Provide 3 variations. EACH MUST BE AT MOST 8 WORDS LONG.
    - FINAL SIGNATURE (closings): Provide 3 professional sign-offs.

    Focus on clarity and business etiquette. Strictly adhere to the 8-word limit for gratitude segments.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          bodies: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          thanks: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Gratitude phrases, maximum 8 words each."
          },
          closings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      },
    },
  });

  try {
    const data = JSON.parse(response.text);
    if (!data.greetings || data.greetings.length === 0) {
      data.greetings = ["Dear Partner", "Dear Customer"];
    }
    return data as MessageParts;
  } catch (error) {
    console.error("Failed to parse JSON response from Gemini", error);
    throw new Error("Invalid response format from AI");
  }
};

import React, { useState, useEffect } from 'react';
