import React, { useState, useEffect, useRef } from 'react';
import { generateMessageParts } from './geminiService';
import { MessageTone, MessageParts, SelectedParts } from './types';
import { 
  Sparkles, 
  Copy, 
  Check, 
  RefreshCw, 
  MessageSquare, 
  Send,
  Coffee,
  Briefcase,
  Heart,
  AlertCircle,
  PenTool,
  Languages,
  CheckCircle2,
  RotateCcw,
  Edit3,
  CheckCheck,
  User,
  Layout,
  Maximize2
} from 'lucide-react';

const App: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [tone, setTone] = useState<MessageTone>(MessageTone.PROFESSIONAL);
  const [responderName, setResponderName] = useState(() => localStorage.getItem('responderName') || '');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<MessageParts | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [selected, setSelected] = useState<SelectedParts>({
    greeting: '',
    body: '',
    thanks: '',
    closing: ''
  });
  const [copied, setCopied] = useState(false);
  const [copiedSegment, setCopiedSegment] = useState<string | null>(null);

  // Persist name in localStorage
  useEffect(() => {
    localStorage.setItem('responderName', responderName);
  }, [responderName]);

  const handleGenerate = async () => {
    setError(null);
    if (!responderName.trim()) {
      setError("Please enter your name to continue. A signature is required.");
      return;
    }
    if (!topic.trim()) {
      setError("Please enter the message text you wish to elaborate.");
      return;
    }

    setLoading(true);
    try {
      const data = await generateMessageParts(topic, tone);
      setResults(data);
      setIsEditing(false);

      const randomGreeting = data.greetings[Math.floor(Math.random() * data.greetings.length)];
      setSelected({
        greeting: randomGreeting || 'Dear Customer',
        body: data.bodies[0] || '',
        thanks: data.thanks[0] || '',
        closing: data.closings[0] || 'Best regards'
      });
    } catch (err: any) {
      setError(err.message || 'An error occurred while generating variations.');
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    const signature = responderName.trim() ? `\n${responderName}` : '';
    const fullText = `${selected.greeting}\n\n${selected.body}\n\n${selected.thanks}\n\n${selected.closing}${signature}`;
    navigator.clipboard.writeText(fullText.trim());
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const copySegment = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopiedSegment(text);
    setTimeout(() => setCopiedSegment(null), 1500);
  };

  const updateSelection = (field: keyof SelectedParts, value: string) => {
    setSelected(prev => ({ ...prev, [field]: value }));
    setIsEditing(false);
  };

  const getToneDescription = (t: MessageTone) => {
    switch (t) {
      case MessageTone.PROFESSIONAL: return "Clear, formal, and objective.";
      case MessageTone.FRIENDLY: return "Warm, helpful, and approachable.";
      case MessageTone.CASUAL: return "Direct, relaxed, and informal.";
      case MessageTone.APOLOGETIC: return "Empathetic and sincere.";
      default: return "";
    }
