import React, { useState, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { 
  Sparkles, Copy, Check, RefreshCw, MessageSquare, Send,
  Coffee, Briefcase, Heart, AlertCircle, PenTool, Languages,
  CheckCircle2, RotateCcw, Edit3, User, Zap, Mail, Trash2,
  CheckCheck, ChevronRight, Share2, MousePointerClick
} from 'lucide-react';

// --- Types ---
enum MessageTone {
  PROFESSIONAL = 'Professional',
  FRIENDLY = 'Friendly',
  CASUAL = 'Casual',
  APOLOGETIC = 'Apologetic'
}

interface MessageParts {
  greetings: string[];
  bodies: string[];
  thanks: string[];
  closings: string[];
}

interface SelectedParts {
  greeting: string;
  body: string;
  thanks: string;
  closing: string;
}

// --- Gemini Logic (Embedded for Standalone) ---
const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Draft input (IT or EN): "${topic}". Tone requested: ${tone}.
    TASK: Generate 3 professional ENGLISH variations for a modular email.
    RESPONSE SCHEMA: JSON with greetings[], bodies[], thanks[] (max 8 words), closings[].`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: { type: Type.ARRAY, items: { type: Type.STRING } },
          bodies: { type: Type.ARRAY, items: { type: Type.STRING } },
          thanks: { type: Type.ARRAY, items: { type: Type.STRING } },
          closings: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      }
    }
  });

  try {
    return JSON.parse(response.text) as MessageParts;
  } catch {
    throw new Error("AI format error. Try again.");
  }
};

// --- Main Component ---
const App: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [tone, setTone] = useState<MessageTone>(MessageTone.PROFESSIONAL);
  const [responderName, setResponderName] = useState(() => localStorage.getItem('reply_ai_name') || '');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<MessageParts | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [selected, setSelected] = useState<SelectedParts>({
    greeting: '', body: '', thanks: '', closing: ''
  });
  const [copied, setCopied] = useState(false);
  const [lastCopiedId, setLastCopiedId] = useState<string | null>(null);

  // Dynamic Theme Mapping
  const theme = useMemo(() => {
    const map = {
      [MessageTone.PROFESSIONAL]: {
