import { GoogleGenAI, Type } from "@google/genai";
import { MessageTone, MessageParts } from "./types";

// The generateMessageParts function creates an English response variation based on user input (EN or IT).
export const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  // Always use the process.env.API_KEY string directly when initializing the GoogleGenAI instance.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `The user has provided a base message in either English or Italian: "${topic}".

    TASK:
    1. If the input is in Italian, translate the core meaning to idiomatic, professional English.
    2. If the input is in English, treat it as the draft to refine.
    3. Generate 3 professional variations of this body text in ENGLISH. 
    4. Each variation should subtly emphasize the requested tone: ${tone}.

    CRITICAL CONSTRAINTS:
    - ALWAYS output in ENGLISH.
    - PERSPECTIVE: You MUST ALWAYS refer to the sender as "WE" (the team/the company). NEVER use "I", "me", "my", or "mine". 
    - Convert singular phrases like "I am writing" to "We are writing", "I would like" to "We would like", and "my request" to "our request".
    - GREETINGS: You MUST include "Dear Partner" as the primary greeting.
    - BODY: 3 variations. They must be fluid, avoid robotic phrasing, and maintain the user's specific intent while polishing the grammar and professional flow.
    - CLOSING COURTESY (thanks): Provide 3 professional "gratitude" segments. EACH MUST BE AT MOST 8 WORDS LONG. Ensure these also use "We/Our" (e.g., "We appreciate your help").
    - FINAL SIGNATURE (closings): Provide 3 standard professional sign-offs (e.g., Best regards, Sincerely, Kind regards).

    Focus on business clarity. Strictly adhere to the 8-word limit for the thank-you segments. Avoid placeholders like [Name] as the user will append their name separately.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          bodies: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          thanks: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Gratitude phrases, maximum 8 words each."
          },
          closings: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      },
    },
  });

  const responseText = response.text || '';

  try {
    const data = JSON.parse(responseText);
    // Ensure "Dear Partner" is always available in the response data
    if (!data.greetings || !data.greetings.includes("Dear Partner")) {
      data.greetings = ["Dear Partner", ...(data.greetings || [])];
    }
    return data as MessageParts;
  } catch (error) {
    console.error("Failed to parse JSON response from Gemini", error);
    throw new Error("Invalid response format from AI. Please try again.");
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { 
  Sparkles, Copy, Check, RefreshCw, MessageSquare, Send,
  Coffee, Briefcase, Heart, AlertCircle, PenTool, Languages,
  CheckCircle2, RotateCcw, Edit3, User, Zap, Mail, Trash2,
  CheckCheck, ChevronRight, Share2, MousePointerClick
} from 'lucide-react';

// --- Types ---
enum MessageTone {
  PROFESSIONAL = 'Professional',
  FRIENDLY = 'Friendly',
  CASUAL = 'Casual',
  APOLOGETIC = 'Apologetic'
}

interface MessageParts {
  greetings: string[];
  bodies: string[];
  thanks: string[];
  closings: string[];
}

interface SelectedParts {
  greeting: string;
  body: string;
  thanks: string;
  closing: string;
}

// --- Gemini Logic (Embedded for Standalone) ---
const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Draft input (IT or EN): "${topic}". Tone requested: ${tone}.
    TASK: Generate 3 professional ENGLISH variations for a modular email.
    PERSPECTIVE: You MUST ALWAYS use "WE" (plural) to refer to the sender. NEVER use "I". 
    Example: change "I am writing" to "We are writing".
    GREETINGS: You MUST include "Dear Partner" as the primary greeting.
    RESPONSE SCHEMA: JSON with greetings[], bodies[], thanks[] (max 8 words), closings[].`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: { type: Type.ARRAY, items: { type: Type.STRING } },
          bodies: { type: Type.ARRAY, items: { type: Type.STRING } },
          thanks: { type: Type.ARRAY, items: { type: Type.STRING } },
          closings: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text) as MessageParts;
    // Ensure "Dear Partner" is always available
    if (!data.greetings.includes("Dear Partner")) {
      data.greetings.unshift("Dear Partner");
    }
    return data;
  } catch {
    throw new Error("AI format error. Try again.");
  }
};

