import React, { useState, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { 
  Sparkles, Copy, Check, RefreshCw, MessageSquare, Send,
  Coffee, Briefcase, Heart, AlertCircle, PenTool, Languages,
  CheckCircle2, RotateCcw, Edit3, User, Zap, Mail, Trash2,
  CheckCheck, ChevronRight, Share2, MousePointerClick, ShieldCheck,
  LayoutGrid, FileText, Palette
} from 'lucide-react';

// --- Types ---
enum MessageTone {
  PROFESSIONAL = 'Professional',
  FRIENDLY = 'Friendly',
  CASUAL = 'Casual',
  APOLOGETIC = 'Apologetic'
}

interface MessageParts {
  greetings: string[];
  bodies: string[];
  thanks: string[];
  closings: string[];
}

interface SelectedParts {
  greeting: string;
  body: string;
  thanks: string;
  closing: string;
}

// --- Gemini Logic ---
const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Draft input (IT or EN): "${topic}". Tone requested: ${tone}.
    TASK: Generate 3 professional ENGLISH variations for a modular email.
    PERSPECTIVE: You MUST ALWAYS use "WE" (plural) to refer to the sender. NEVER use "I". 
    Example: change "I am writing" to "We are writing".
    GREETINGS: You MUST include "Dear Partner" as the primary greeting.
    RESPONSE SCHEMA: JSON with greetings[], bodies[], thanks[] (max 8 words), closings[].`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: { type: Type.ARRAY, items: { type: Type.STRING } },
          bodies: { type: Type.ARRAY, items: { type: Type.STRING } },
          thanks: { type: Type.ARRAY, items: { type: Type.STRING } },
          closings: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text) as MessageParts;
    if (!data.greetings.includes("Dear Partner")) {
      data.greetings.unshift("Dear Partner");
    }
    return data;
  } catch {
    throw new Error("AI format error. Try again.");
  }
};

