import { GoogleGenAI, Type } from "@google/genai";
import { MessageTone, MessageParts } from "./types";

export const generateMessageParts = async (topic: string, tone: MessageTone): Promise<MessageParts> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Draft input (IT or EN): "${topic}". Tone requested: ${tone}.

    TASK: Generate 3 professional ENGLISH variations for a modular email.

    STRICT RULE - PRESERVATION: If the input contains text inside double quotes (e.g., "lemon", "Project X"), you MUST preserve those exact quoted strings verbatim in all generated variations. Do not translate or rephrase words inside quotes.

    PERSPECTIVE: You MUST ALWAYS use "WE" (plural) to refer to the sender. NEVER use "I", "me", or "my". 
    Example: change "I am writing" to "We are writing", "I would like" to "We would like".

    GREETINGS: You MUST include "Dear Partner" as the primary greeting.

    RESPONSE SCHEMA: JSON with:
    - greetings: array of strings
    - bodies: array of strings (the main message)
    - thanks: array of strings (max 8 words each, e.g., "We appreciate your prompt attention")
    - closings: array of strings (standard sign-offs)`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greetings: { type: Type.ARRAY, items: { type: Type.STRING } },
          bodies: { type: Type.ARRAY, items: { type: Type.STRING } },
          thanks: { type: Type.ARRAY, items: { type: Type.STRING } },
          closings: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["greetings", "bodies", "thanks", "closings"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text) as MessageParts;
    if (!data.greetings.includes("Dear Partner")) {
      data.greetings.unshift("Dear Partner");
    }
    return data;
  } catch {
    throw new Error("AI communication error. Please try again.");
  }
};

